// --- Token Management ---

// ServiceToken represents an internal service mesh token
type ServiceToken struct {
	ServiceName string
	IssuedAt    time.Time
	ExpiresAt   time.Time
	Permissions []string
	Signature   string
}

// TokenStore manages valid service tokens
type TokenStore struct {
	mu        sync.RWMutex
	tokens    map[string]*ServiceToken
	secretKey []byte
}

func NewTokenStore(secretKey string) *TokenStore {
	return &TokenStore{
		tokens:    make(map[string]*ServiceToken),
		secretKey: []byte(secretKey),
	}
}

func (ts *TokenStore) GenerateToken(serviceName string, permissions []string, ttl time.Duration) (string, error) {
	ts.mu.Lock()
	defer ts.mu.Unlock()

	now := time.Now()
	token := &ServiceToken{
		ServiceName: serviceName,
		IssuedAt:    now,
		ExpiresAt:   now.Add(ttl),
		Permissions: permissions,
	}

	// Create HMAC signature
	data := fmt.Sprintf("%s:%d:%d:%s", serviceName, now.Unix(), token.ExpiresAt.Unix(), strings.Join(permissions, ","))
	mac := hmac.New(sha256.New, ts.secretKey)
	mac.Write([]byte(data))
	signature := hex.EncodeToString(mac.Sum(nil))

	token.Signature = signature

	// The token string is: serviceName:issuedAt:expiresAt:signature
	tokenStr := fmt.Sprintf("%s:%d:%d:%s", serviceName, now.Unix(), token.ExpiresAt.Unix(), signature)
	ts.tokens[tokenStr] = token

	return tokenStr, nil
}

func (ts *TokenStore) ValidateToken(tokenStr string) (*ServiceToken, error) {
	ts.mu.RLock()
	defer ts.mu.RUnlock()

	// Parse the token
	parts := strings.SplitN(tokenStr, ":", 4)
	if len(parts) != 4 {
		return nil, fmt.Errorf("invalid token format")
	}

	serviceName := parts[0]
	signature := parts[3]

	// Recompute HMAC to verify
	data := fmt.Sprintf("%s:%s:%s:%s", serviceName, parts[1], parts[2],
		func() string {
			// Get permissions from stored token if exists
			if t, ok := ts.tokens[tokenStr]; ok {
				return strings.Join(t.Permissions, ",")
			}
			return ""
		}())
	mac := hmac.New(sha256.New, ts.secretKey)
	mac.Write([]byte(data))
	expectedSig := hex.EncodeToString(mac.Sum(nil))

	if !hmac.Equal([]byte(signature), []byte(expectedSig)) {
		return nil, fmt.Errorf("invalid token signature")
	}

	token, exists := ts.tokens[tokenStr]
	if !exists {
		return nil, fmt.Errorf("token not found")
	}

	if time.Now().After(token.ExpiresAt) {
		delete(ts.tokens, tokenStr)
		return nil, fmt.Errorf("token expired")
	}

	return token, nil
}

func (ts *TokenStore) RevokeToken(tokenStr string) {
	ts.mu.Lock()
	defer ts.mu.Unlock()
	delete(ts.tokens, tokenStr)
}

