func UnaryAuthInterceptor(tokenStore *TokenStore) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		// Skip auth for health check
		if info.FullMethod == "/mesh.MeshService/HealthCheck" {
			return handler(ctx, req)
		}

		authCtx, err := authenticate(ctx, tokenStore)
		if err != nil {
			log.Printf("Authentication failed for %s: %v", info.FullMethod, err)
			return nil, err
		}

		authInfo, _ := AuthInfoFromContext(authCtx)
		log.Printf("Authenticated request from service '%s' to %s", authInfo.ServiceName, info.FullMethod)

		// Check method-level permissions
		if err := checkPermission(authInfo, info.FullMethod); err != nil {
			return nil, err
		}

		return handler(authCtx, req)
	}
}

func StreamAuthInterceptor(tokenStore *TokenStore) grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		ss grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		authCtx, err := authenticate(ss.Context(), tokenStore)
		if err != nil {
			log.Printf("Stream authentication failed for %s: %v", info.FullMethod, err)
			return err
		}

		authInfo, _ := AuthInfoFromContext(authCtx)
		log.Printf("Authenticated stream from service '%s' to %s", authInfo.ServiceName, info.FullMethod)

		if err := checkPermission(authInfo, info.FullMethod); err != nil {
			return err
		}

		wrapped := &authenticatedServerStream{
			ServerStream: ss,
			ctx:          authCtx,
		}
		return handler(srv, wrapped)
	}
}

type authenticatedServerStream struct {
	grpc.ServerStream
	ctx context.Context
}

func (s *authenticatedServerStream) Context() context.Context {
	return s.ctx
}

func authenticate(ctx context.Context, tokenStore *TokenStore) (context.Context, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "missing metadata")
	}

	// Extract authorization token
	authHeaders := md.Get("authorization")
	if len(authHeaders) == 0 {
		return nil, status.Error(codes.Unauthenticated, "missing authorization token")
	}

	tokenStr := authHeaders[0]
	// Support "Bearer <token>" format
	if strings.HasPrefix(tokenStr, "Bearer ") {
		tokenStr = strings.TrimPrefix(tokenStr, "Bearer ")
	}

	// Validate the token
	token, err := tokenStore.ValidateToken(tokenStr)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "invalid token: %v", err)
	}

	// Extract optional service identity headers (for mesh tracing)
	var sourceService string
	if svc := md.Get("x-source-service"); len(svc) > 0 {
		sourceService = svc[0]
		// Verify source service matches token
		if sourceService != token.ServiceName {
			return nil, status.Error(codes.PermissionDenied, "source service mismatch with token")
		}
	}

	// Extract request ID for tracing
	var requestID string
	if rid := md.Get("x-request-id"); len(rid) > 0 {
		requestID = rid[0]
		log.Printf("Request ID: %s", requestID)
	}

	_ = requestID

	authInfo := &AuthInfo{
		ServiceName: token.ServiceName,
		Permissions: token.Permissions,
		Token:       token,
	}

	newCtx := context.WithValue(ctx, authContextKey{}, authInfo)
	return newCtx, nil
}

// Permission mapping: method -> required permission
var methodPermissions = map[string]string{
	"/mesh.MeshService/GetData":       "read",
	"/mesh.MeshService/PutData":       "write",
	"/mesh.MeshService/DeleteData":    "admin",
	"/mesh.MeshService/StreamData":    "read",
	"/mesh.MeshService/ServiceStatus": "read",
}

func checkPermission(authInfo *AuthInfo, fullMethod string) error {
	requiredPerm, exists := methodPermissions[fullMethod]
	if !exists {
		// Default: require at least one permission
		if len(authInfo.Permissions) == 0 {
			return status.Error(codes.PermissionDenied, "no permissions granted")
		}
		return nil
	}

	for _, perm := range authInfo.Permissions {
		if perm == requiredPerm || perm == "admin" {
			return nil
		}
	}

	return status.Errorf(codes.PermissionDenied, "missing required permission: %s", requiredPerm)
}

