func (s *MeshServiceServer) HealthCheck(ctx context.Context, req *HealthCheckRequest) (*HealthCheckResponse, error) {
	return &HealthCheckResponse{
		Status:  "SERVING",
		Service: "mesh-data-service",
	}, nil
}

func (s *MeshServiceServer) GetData(ctx context.Context, req *GetDataRequest) (*GetDataResponse, error) {
	authInfo, ok := AuthInfoFromContext(ctx)
	if !ok {
		return nil, status.Error(codes.Internal, "auth info not found in context")
	}

	log.Printf("[GetData] Service '%s' requesting key: %s", authInfo.ServiceName, req.Key)

	value, ok := s.store.Load(req.Key)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "key '%s' not found", req.Key)
	}

	return &GetDataResponse{
		Key:   req.Key,
		Value: value.(string),
	}, nil
}

func (s *MeshServiceServer) PutData(ctx context.Context, req *PutDataRequest) (*PutDataResponse, error) {
	authInfo, ok := AuthInfoFromContext(ctx)
	if !ok {
		return nil, status.Error(codes.Internal, "auth info not found in context")
	}

	log.Printf("[PutData] Service '%s' storing key: %s", authInfo.ServiceName, req.Key)

	s.store.Store(req.Key, req.Value)

	return &PutDataResponse{
		Success: true,
		Message: fmt.Sprintf("Key '%s' stored successfully by service '%s'", req.Key, authInfo.ServiceName),
	}, nil
}

func (s *MeshServiceServer) DeleteData(ctx context.Context, req *DeleteDataRequest) (*DeleteDataResponse, error) {
	authInfo, ok := AuthInfoFromContext(ctx)
	if !ok {
		return nil, status.Error(codes.Internal, "auth info not found in context")
	}

	log.Printf("[DeleteData] Service '%s' (admin) deleting key: %s", authInfo.ServiceName, req.Key)

	s.store.Delete(req.Key)

	return &DeleteDataResponse{
		Success: true,
	}, nil
}

func (s *MeshServiceServer) ServiceStatus(ctx context.Context, req *ServiceStatusRequest) (*ServiceStatusResponse, error) {
	authInfo, ok := AuthInfoFromContext(ctx)
	if !ok {
		return nil, status.Error(codes.Internal, "auth info not found in context")
	}

	log.Printf("[ServiceStatus] Requested by service '%s'", authInfo.ServiceName)

	return &ServiceStatusResponse{
		ServiceName: "mesh-data-service",
		Uptime:      time.Since(s.startTime).String(),
	}, nil
}

