func demonstrateClientCalls(orderToken, inventoryToken, adminToken string) {
	log.Println("\n--- Starting client demonstration ---")

	conn, err := grpc.Dial("localhost:50051", grpc.WithInsecure())
	if err != nil {
		log.Printf("Failed to connect: %v", err)
		return
	}
	defer conn.Close()

	// Test 1: Unauthenticated request (should fail)
	log.Println("\n[Test 1] Unauthenticated request...")
	ctx := context.Background()
	err = conn.Invoke(ctx, "/mesh.MeshService/GetData", &GetDataRequest{Key: "test"}, &GetDataResponse{})
	if err != nil {
		log.Printf("  Expected error: %v", err)
	}

	// Test 2: Authenticated PutData from order-service
	log.Println("\n[Test 2] order-service PutData...")
	ctx = metadata.NewOutgoingContext(context.Background(), metadata.Pairs(
		"authorization", "Bearer "+orderToken,
		"x-source-service", "order-service",
		"x-request-id", "req-001",
	))
	putResp := &PutDataResponse{}
	err = conn.Invoke(ctx, "/mesh.MeshService/PutData", &PutDataRequest{Key: "order-123", Value: "pending"}, putResp)
	if err != nil {
		log.Printf("  Error: %v", err)
	} else {
		log.Printf("  Success: %s", putResp.Message)
	}

	// Test 3: Authenticated GetData from inventory-service
	log.Println("\n[Test 3] inventory-service GetData...")
	ctx = metadata.NewOutgoingContext(context.Background(), metadata.Pairs(
		"authorization", "Bearer "+inventoryToken,
		"x-source-service", "inventory-service",
		"x-request-id", "req-002",
	))
	getResp := &GetDataResponse{}
	err = conn.Invoke(ctx, "/mesh.MeshService/GetData", &GetDataRequest{Key: "order-123"}, getResp)
	if err != nil {
		log.Printf("  Error: %v", err)
	} else {
		log.Printf("  Got: %s = %s", getResp.Key, getResp.Value)
	}

	// Test 4: inventory-service trying to write (should fail - no write permission)
	log.Println("\n[Test 4] inventory-service PutData (should fail - no write permission)...")
	ctx = metadata.NewOutgoingContext(context.Background(), metadata.Pairs(
		"authorization", "Bearer "+inventoryToken,
		"x-source-service", "inventory-service",
		"x-request-id", "req-003",
	))
	err = conn.Invoke(ctx, "/mesh.MeshService/PutData", &PutDataRequest{Key: "hack", Value: "bad"}, &PutDataResponse{})
	if err != nil {
		log.Printf("  Expected error: %v", err)
	}

	// Test 5: admin-service DeleteData
	log.Println("\n[Test 5] admin-service DeleteData...")
	ctx = metadata.NewOutgoingContext(context.Background(), metadata.Pairs(
		"authorization", "Bearer "+adminToken,
		"x-source-service", "admin-service",
		"x-request-id", "req-004",
	))
	delResp := &DeleteDataResponse{}
	err = conn.Invoke(ctx, "/mesh.MeshService/DeleteData", &DeleteDataRequest{Key: "order-123"}, delResp)
	if err != nil {
		log.Printf("  Error: %v", err)
	} else {
		log.Printf("  Deleted: %v", delResp.Success)
	}

	// Test 6: Service status
	log.Println("\n[Test 6] order-service ServiceStatus...")
	ctx = metadata.NewOutgoingContext(context.Background(), metadata.Pairs(
		"authorization", "Bearer "+orderToken,
		"x-source-service", "order-service",
		"x-request-id", "req-005",
	))
	statusResp := &ServiceStatusResponse{}
	err = conn.Invoke(ctx, "/mesh.MeshService/ServiceStatus", &ServiceStatusRequest{}, statusResp)
	if err != nil {
		log.Printf("  Error: %v", err)
	} else {
		log.Printf("  Service: %s, Uptime: %s", statusResp.ServiceName, statusResp.Uptime)
	}

	// Test 7: Source service mismatch (should fail)
	log.Println("\n[Test 7] Token/service mismatch (should fail)...")
	ctx = metadata.NewOutgoingContext(context.Background(), metadata.Pairs(
		"authorization", "Bearer "+orderToken,
		"x-source-service", "fake-service", // Mismatch!
		"x-request-id", "req-006",
	))
	err = conn.Invoke(ctx, "/mesh.MeshService/GetData", &GetDataRequest{Key: "test"}, &GetDataResponse{})
	if err != nil {
		log.Printf("  Expected error: %v", err)
	}

	// Test 8: Health check (no auth required)
	log.Println("\n[Test 8] Health check (no auth required)...")
	ctx = context.Background()
	healthResp := &HealthCheckResponse{}
	err = conn.Invoke(ctx, "/mesh.MeshService/HealthCheck", &HealthCheckRequest{}, healthResp)
	if err != nil {
		log.Printf("  Error: %v", err)
	} else {
		log.Printf("  Health: %s (%s)", healthResp.Status, healthResp.Service)
	}

	log.Println("\n--- Client demonstration complete ---")
}